@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-item-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel);
}

@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => HandleReact(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="HandleOpenThread">
            @ThreadSummary.ReplyCount replies
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="HandleOpenThread" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="() => showEmojiPicker = !showEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-option" @onclick="() => HandleReact(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private async Task HandleOpenThread()
    {
        await OnOpenThread.InvokeAsync(Message.Id);
    }

    private async Task HandleReact(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="message-input-area">
    <textarea class="message-textarea"
              @bind="messageText"
              @bind:event="oninput"
              placeholder="@Placeholder"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(messageText)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string messageText = string.Empty;

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(messageText)) return;
        var text = messageText.Trim();
        messageText = string.Empty;
        await OnSend.InvokeAsync(text);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}

@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="message-area">
    @if (ChannelName is not null)
    {
        <div class="message-area-header">
            <h4># @ChannelName</h4>
            <p class="channel-desc">@ChannelDescription</p>
        </div>

        <div class="message-list" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var message in Messages)
            {
                <MessageBubble Message="message"
                               ThreadSummary="GetThreadSummary(message.Id)"
                               OnOpenThread="OnOpenThread"
                               OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Message #@ChannelName" ButtonText="Send" OnSend="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = new();
    [Parameter] public string? ChannelName { get; set; }
    [Parameter] public string? ChannelDescription { get; set; }
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers load more (JS interop would be needed for precise detection)
        // For now, we expose the callback; the page handles pagination
        await OnLoadMore.InvokeAsync();
    }
}

@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonText="Reply" OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

