@page "/chat"
@namespace sv_c39bf83dd4dd4fe980449c482e098a99.Components.Pages.Chat
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannel?.Id"
                    OnChannelSelected="HandleChannelSelected" />

    <div class="chat-main @(threadOpen ? "with-thread" : "")">
        <MessageArea Messages="messages"
                     ChannelName="@selectedChannel?.Name"
                     ChannelDescription="@selectedChannel?.Description"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnOpenThread="HandleOpenThread"
                     OnReact="HandleReact"
                     OnSendMessage="HandleSendMessage"
                     OnLoadMore="HandleLoadMore" />
    </div>

    @if (threadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private List<ThreadSummary> threadSummaries = new();
    private bool isLoadingMore;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    // Pagination
    private const int PageSize = 30;
    private int currentSkip;
    private bool hasMoreMessages = true;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await HandleChannelSelected(channels[0]);
        }
    }

    private async Task HandleChannelSelected(Channel channel)
    {
        selectedChannel = channel;
        currentSkip = 0;
        hasMoreMessages = true;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        currentSkip = messages.Count;
        threadSummaries = BuildThreadSummaries(messages);
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task HandleLoadMore()
    {
        if (isLoadingMore || !hasMoreMessages) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel!.Id, currentSkip, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);
        currentSkip += older.Count;
        threadSummaries = BuildThreadSummaries(messages);
        isLoadingMore = false;
    }

    private async Task HandleSendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task HandleOpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;
        threadReplies = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private void HandleCloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
    }

    private async Task HandleSendReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary
        threadSummaries = BuildThreadSummaries(messages, threadRootMessage.Id, threadReplies.Count);
    }

    private async Task HandleReact((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Optimistically update the local message
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, new List<string> { "You" }));
            }
        }
    }

    private static List<ThreadSummary> BuildThreadSummaries(List<Message> msgs, int? updatedThreadId = null, int? updatedCount = null)
    {
        var summaries = new List<ThreadSummary>();
        var rootIds = msgs.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();
        var replies = msgs.Where(m => m.ReplyToId is not null).GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replies)
        {
            if (rootIds.Contains(group.Key))
            {
                summaries.Add(new ThreadSummary(group.Key, group.Count(), group.Max(m => m.SentAt)));
            }
        }

        if (updatedThreadId.HasValue && updatedCount.HasValue)
        {
            var existing = summaries.FindIndex(s => s.RootMessageId == updatedThreadId.Value);
            if (existing >= 0)
            {
                summaries[existing] = new ThreadSummary(updatedThreadId.Value, updatedCount.Value, DateTime.UtcNow);
            }
            else
            {
                summaries.Add(new ThreadSummary(updatedThreadId.Value, updatedCount.Value, DateTime.UtcNow));
            }
        }

        return summaries;
    }
}

